class NormalizedCrossCorrelation2d(torch.nn.Module):
    """Compute Normalized Cross Correlation between two batches of images with circular mask."""

    def __init__(self, patch_size=None, eps=1e-3, image_size=256, radius=120, device=torch.device('cpu'), step=1):
        super().__init__()
        self.patch_size = patch_size
        self.eps = eps
        self.image_size = image_size
        self.radius = radius
        self.step = step

    @staticmethod
    def create_mask(image_size, radius, patch_size=None, step=1):
        center = (image_size - 1) / 2  # Center at 127.5 for 256x256
        y = torch.arange(image_size, dtype=torch.float32)
        x = torch.arange(image_size, dtype=torch.float32)
        yy, xx = torch.meshgrid(y, x, indexing='ij')
        dist_sq = (xx - center) ** 2 + (yy - center) ** 2
        mask = (dist_sq <= radius ** 2).float().unsqueeze(0).unsqueeze(0)
        if patch_size is not None:
            mask = to_patches(mask, patch_size, step)
        return mask # Shape: (1, 1, H, W)

    def forward(self, x1, x2, mask=None):
        if mask == None: mask = torch.ones_like(x1).to(x1.device)
        if self.patch_size is not None:
            x1 = to_patches(x1, self.patch_size, step=self.step)
            x2 = to_patches(x2, self.patch_size, step=self.step)
            mask = to_patches(mask, self.patch_size, step=self.step).to(x1.device)
        # plt.figure()
        # plt.imshow(mask.cpu().squeeze(0).permute(1, 2, 0), cmap='gray')
        # plt.show()

        valid = mask.sum(dim=[-2, -1], keepdim=True) <= 30
        idx = torch.where(~valid)
        valid_idx = idx[1]
        valid_idx = valid_idx
        mask = mask[:, valid_idx, :, :]

        assert x1.shape == x2.shape, "Input images must be the same size"

        x1 = x1[:, valid_idx, :, :]
        x2 = x2[:, valid_idx, :, :]
        x1 = x1 * mask
        x2 = x2 * mask

        _, c, h, w = x1.shape
        x1, x2 = self.norm(x1, mask), self.norm(x2, mask)

        score = torch.einsum("b...,b...->b", x1, x2)
        effective_pixels = mask.sum() # Total valid pixels per batch
        score /= effective_pixels + self.eps

        return score

    def norm(self, x, mask):
        mu = (x * mask).sum(dim=[-2, -1], keepdim=True) / (mask.sum(dim=[-2, -1], keepdim=True) + self.eps)
        x_centered = (x - mu) * mask
        var = (x_centered ** 2).sum(dim=[-2, -1], keepdim=True) / (mask.sum(dim=[-2, -1], keepdim=True) + self.eps)
        std = var.sqrt()
        return x_centered / (std + self.eps)

class MultiscaleNormalizedCrossCorrelation2d(torch.nn.Module):
    """Compute Normalized Cross Correlation between two batches of images at multiple scales."""
    def __init__(self, patch_sizes=[None], patch_weights=[1.0], eps=1e-5, device=torch.device('cpu'), step=[1]):
        super().__init__()

        assert len(patch_sizes) == len(patch_weights), "Each scale must have a weight"
        self.nccs = [
            NormalizedCrossCorrelation2d(patch_size, device=device, step=s) for patch_size, s in zip(patch_sizes, step)
        ]
        self.patch_weights = patch_weights

    def forward(self, x1, x2, mask=None):
        scores = []
        for weight, ncc in zip(self.patch_weights, self.nccs):
            scores.append(weight * ncc(x1, x2, mask))
        return torch.stack(scores, dim=0).sum(dim=0)

    def set_mask(self, tube_mask):
        for ncc in self.nccs:
            ncc.set_mask(tube_mask)

